func (s *Service) ProcessPayment(userID string, amount float64, transactionID string) (Transaction, bool, error) {
	if existingTx, exists := s.txStore.Get(transactionID); exists {
		return existingTx, true, nil
	}

	newTx := Transaction{
		TransactionID: transactionID,
		UserID:        userID,
		Amount:        amount,
		Status:        "pending",
	}
	s.txStore.Set(transactionID, newTx)

	// Simulate async processing
	delay := s.processingDelay
	go func(txID string) {
		if delay > 0 {
			time.Sleep(delay)
		}
		s.txStore.Update(txID, func(tx Transaction) Transaction {
			tx.Status = "processed"
			return tx
		})
	}(transactionID)

	return newTx, false, nil
}

func (s *Service) ProcessTasks(numTasks, poolSize int) ([]Result, time.Duration, error) {
	start := time.Now()
	tasks := make(chan Task, numTasks)
	results := make(chan Result, numTasks)

	// Spawn worker goroutines
	for w := 1; w <= poolSize; w++ {
		go s.worker(w, tasks, results)
	}

	// Send all tasks
	for i := 1; i <= numTasks; i++ {
		tasks <- Task{ID: i, Input: i}
	}
	close(tasks)

	// Collect results
	resultSlice := make([]Result, 0, numTasks)
	for i := 0; i < numTasks; i++ {
		resultSlice = append(resultSlice, <-results)
	}
	close(results)

	// Sort by TaskID to maintain order
	sort.Slice(resultSlice, func(i, j int) bool {
		return resultSlice[i].TaskID < resultSlice[j].TaskID
	})

	return resultSlice, time.Since(start), nil
}

